    // --- Discovery ---

    /**
     * Discover IoT devices on the local network by probing common endpoints.
     */
    fun discoverDevices(
        subnet: String = "192.168.1",
        port: Int = 80,
        discoveryPath: String = "/api/info",
        callback: DeviceDiscoveryCallback
    ) {
        if (!isLocalSubnet(subnet)) {
            callback.onError(SecurityException("Subnet $subnet is not a local network"))
            return
        }

        val discoveredDevices = mutableListOf<DiscoveredDevice>()
        val latch = java.util.concurrent.CountDownLatch(254)

        for (i in 1..254) {
            val ip = "$subnet.$i"
            val url = "http://$ip:$port$discoveryPath"

            val request = Request.Builder()
                .url(url)
                .get()
                .tag("discovery")
                .build()

            // Use a shorter timeout for discovery
            val discoveryClient = localClient.newBuilder()
                .connectTimeout(2, TimeUnit.SECONDS)
                .readTimeout(2, TimeUnit.SECONDS)
                .build()

            discoveryClient.newCall(request).enqueue(object : Callback {
                override fun onFailure(call: Call, e: IOException) {
                    latch.countDown()
                    if (latch.count == 0L) {
                        callback.onDiscoveryComplete(discoveredDevices.toList())
                    }
                }

                override fun onResponse(call: Call, response: Response) {
                    response.use {
                        if (it.isSuccessful) {
                            val body = it.body?.string()
                            synchronized(discoveredDevices) {
                                discoveredDevices.add(DiscoveredDevice(ip, port, body))
                            }
                        }
                    }
                    latch.countDown()
                    if (latch.count == 0L) {
                        callback.onDiscoveryComplete(discoveredDevices.toList())
                    }
                }
            })
        }
    }

    // --- Internal Helpers ---

    private fun executeAsync(client: OkHttpClient, request: Request, callback: IoTCallback) {
        client.newCall(request).enqueue(object : Callback {
            override fun onFailure(call: Call, e: IOException) {
                callback.onFailure(e)
            }

            override fun onResponse(call: Call, response: Response) {
                response.use {
                    val responseBody = it.body?.string()
                    val iotResponse = IoTResponse(
                        code = it.code,
                        body = responseBody,
                        headers = it.headers.toMap()
                    )

                    if (it.isSuccessful) {
                        callback.onSuccess(iotResponse)
                    } else {
                        callback.onError(iotResponse)
                    }
                }
            }
        })
    }

    @Throws(IOException::class)
    private fun executeSync(client: OkHttpClient, request: Request): IoTResponse {
        val response = client.newCall(request).execute()
        return response.use {
            IoTResponse(
                code = it.code,
                body = it.body?.string(),
                headers = it.headers.toMap()
            )
        }
    }

