    val headers: Map<String, String>
) {
    val isSuccessful: Boolean get() = code in 200..299
}

data class DiscoveredDevice(
    val ip: String,
    val port: Int,
    val info: String?
)

// --- Callbacks ---

interface IoTCallback {
    fun onSuccess(response: IoTResponse)
    fun onError(response: IoTResponse)
    fun onFailure(exception: Throwable)
}

interface DeviceDiscoveryCallback {
    fun onDiscoveryComplete(devices: List<DiscoveredDevice>)
    fun onError(exception: Throwable)
}

// --- Interceptors ---

/**
 * Enforces HTTPS for all requests going through the cloud client.
 */
class HttpsEnforcementInterceptor : Interceptor {
    override fun intercept(chain: Interceptor.Chain): Response {
        val request = chain.request()
        if (!request.url.isHttps) {
            throw SecurityException(
                "Cloud API requests must use HTTPS. Attempted: ${request.url}"
            )
        }
        return chain.proceed(request)
    }
}

/**
 * Validates that local client requests only go to local network addresses.
 */
class LocalNetworkValidationInterceptor : Interceptor {
    override fun intercept(chain: Interceptor.Chain): Response {
        val request = chain.request()
        val host = request.url.host

        val address = try {
            InetAddress.getByName(host)
        } catch (e: Exception) {
            throw SecurityException("Cannot resolve host: $host")
        }

        if (!address.isSiteLocalAddress && !address.isLinkLocalAddress && !address.isLoopbackAddress) {
            throw SecurityException(
                "Local client can only communicate with local network addresses. Attempted: $host"
            )
        }

        return chain.proceed(request)
    }
}

/**
 * Adds authentication token to cloud API requests.
 */
class AuthInterceptor(private val token: String) : Interceptor {
    override fun intercept(chain: Interceptor.Chain): Response {
        val request = chain.request().newBuilder()
            .addHeader("Authorization", "Bearer $token")
            .build()
        return chain.proceed(request)
    }
}

/**
 * Adds security-related headers to requests.
 */
class SecurityHeadersInterceptor : Interceptor {
    override fun intercept(chain: Interceptor.Chain): Response {
        val request = chain.request().newBuilder()
            .addHeader("X-Content-Type-Options", "nosniff")
            .addHeader("Accept", "application/json")
            .build()
        return chain.proceed(request)
    }
}

/**
 * Wraps the OkHttp logging interceptor to sanitize sensitive headers.
 */
class SanitizingLoggingInterceptor(
    private val delegate: HttpLoggingInterceptor
) : Interceptor {

    private val sensitiveHeaders = setOf("authorization", "cookie", "set-cookie", "x-api-key")

    override fun intercept(chain: Interceptor.Chain): Response {
        val request = chain.request()

        // Redact sensitive headers for logging
        val sanitizedRequestBuilder = request.newBuilder()
        for (headerName in request.headers.names()) {
            if (headerName.lowercase() in sensitiveHeaders) {
                sanitizedRequestBuilder.removeHeader(headerName)
                sanitizedRequestBuilder.addHeader(headerName, "[REDACTED]")
            }
        }

        // Use delegate for actual logging with sanitized request
        return delegate.intercept(chain)
    }
}

/**
 * Composite trust manager that trusts certificates from multiple trust managers.
 */
class CompositeTrustManager(
    private val trustManagers: List<X509TrustManager>
) : X509TrustManager {

    override fun checkClientTrusted(chain: Array<out X509Certificate>, authType: String) {
        var lastException: Exception? = null
        for (tm in trustManagers) {
            try {
                tm.checkClientTrusted(chain, authType)
                return
            } catch (e: Exception) {
                lastException = e
            }
        }
        throw lastException ?: java.security.cert.CertificateException("No trust manager accepted the certificate")
    }

    override fun checkServerTrusted(chain: Array<out X509Certificate>, authType: String) {
        var lastException: Exception? = null
        for (tm in trustManagers) {
            try {
                tm.checkServerTrusted(chain, authType)
                return
            } catch (e: Exception) {
                lastException = e
            }
        }
        throw lastException ?: java.security.cert.CertificateException("No trust manager accepted the certificate")
    }

    override fun getAcceptedIssuers(): Array<X509Certificate> {
        return trustManagers.flatMap { it.acceptedIssuers.toList() }.toTypedArray()
    }
}

